import{_ as p,c as t,o as s,a5 as r}from"./chunks/framework.DwbewbAn.js";const o="/assets/image-20220125010118745.CYZ_jNVV.png",a="/assets/image-20220125010148523.D21sf87F.png",e="/assets/image-20220125010228444.s9X0RW4d.png",T="/assets/image-20220125010309686.CUUfK6QB.png",n="/assets/image-20220125010327465.BVcAB4pN.png",g="/assets/image-20220125010523105.xQIo9nNg.png",P="/assets/image-20220125010539558.ClJIcME8.png",L=JSON.parse('{"title":"问题","description":"","frontmatter":{},"headers":[],"relativePath":"doc/网络协议/问题/问题.md","filePath":"packages/doc/src/网络协议/问题/问题.md","lastUpdated":1704643216000}'),i={name:"doc/网络协议/问题/问题.md"},m=r('<h1 id="问题" tabindex="-1">问题 <a class="header-anchor" href="#问题" aria-label="Permalink to &quot;问题&quot;">​</a></h1><h2 id="_1-说说-http-1-1-相比-http-1-0-提高了什么性能" tabindex="-1">1.说说 HTTP/1.1 相比 HTTP/1.0 提高了什么性能？ <a class="header-anchor" href="#_1-说说-http-1-1-相比-http-1-0-提高了什么性能" aria-label="Permalink to &quot;1.说说 HTTP/1.1 相比 HTTP/1.0 提高了什么性能？&quot;">​</a></h2><p>HTTP/1.1 相比 HTTP/1.0 性能上的改进：</p><p>使用 TCP 长连接的方式改善了 HTTP/1.0 短连接造成的性能开销。</p><p>支持管道（pipeline）网络传输，只要第一个请求发出去了，不必等其回来，就可以发第二个请求</p><p>出去，可以减少整体的响应时间。</p><p>但 HTTP/1.1 还是有性能瓶颈：</p><p>请求 / 响应头部（Header）未经压缩就发送，首部信息越多延迟越大。只能压缩 Body 的部分；</p><p>发送冗长的首部。每次互相发送相同的首部造成的浪费较多；</p><p>服务器是按请求的顺序响应的，如果服务器响应慢，会招致客户端一直请求不到数据，也就是队</p><p>头阻塞；</p><p>没有请求优先级控制；</p><p>请求只能从客户端开始，服务器只能被动响应。</p><h2 id="_2-那上面的-http-1-1-的性能瓶颈-http-2-做了什么优化" tabindex="-1">2.那上面的 HTTP/1.1 的性能瓶颈，HTTP/2 做了什么优化？ <a class="header-anchor" href="#_2-那上面的-http-1-1-的性能瓶颈-http-2-做了什么优化" aria-label="Permalink to &quot;2.那上面的 HTTP/1.1 的性能瓶颈，HTTP/2 做了什么优化？&quot;">​</a></h2><p>HTTP/2 协议是基于 HTTPS 的，所以 HTTP/2 的安全性也是有保障的。</p><p>那 HTTP/2 相比 HTTP/1.1 性能上的改进：</p><p><em>1.</em> 头部压缩</p><p>HTTP/2 会<strong>压缩头</strong>（Header）如果你同时发出多个请求，他们的头是一样的或是相似的，那么，协议会</p><p>帮你<strong>消除重复的部分</strong>。</p><p>这就是所谓的 HPACK 算法：在客户端和服务器同时维护一张头信息表，所有字段都会存入这个表，</p><p>生成一个索引号，以后就不发送同样字段了，只发送索引号，这样就<strong>提高速度</strong>了。</p><p><em>2.</em> 二进制格式</p><p>HTTP/2 不再像 HTTP/1.1 里的纯文本形式的报文，而是全面采用了<strong>二进制格式</strong>，头信息和数据体都是</p><p>二进制，并且统称为帧（frame）：<strong>头信息帧和数据帧</strong>。</p><p><img src="'+o+'" alt="image-20220125010118745"></p><p>这样虽然对人不友好，但是对计算机非常友好，因为计算机只懂二进制，那么收到报文后，无需再将明</p><p>文的报文转成二进制，而是直接解析二进制报文，这<strong>增加了数据传输的效率</strong>。</p><p><em>3.</em> 数据流</p><p>HTTP/2 的数据包不是按顺序发送的，同一个连接里面连续的数据包，可能属于不同的回应。因此，必</p><p>须要对数据包做标记，指出它属于哪个回应。</p><p>每个请求或回应的所有数据包，称为一个数据流（ Stream ）。每个数据流都标记着一个独一无二的编</p><p>号，其中规定客户端发出的数据流编号为奇数， 服务器发出的数据流编号为偶数</p><p>客户端还可以<strong>指定数据流的优先级</strong>。优先级高的请求，服务器就先响应该请求。</p><p><img src="'+a+'" alt="image-20220125010148523"></p><p><em>4.</em> 多路复用</p><p>HTTP/2 是可以在<strong>一个连接中并发多个请求或回应，而不用按照顺序一一对应</strong>。</p><p>移除了 HTTP/1.1 中的串行请求，不需要排队等待，也就不会再出现「队头阻塞」问题，<strong>降低了延迟，</strong></p><p><strong>大幅度提高了连接的利用率</strong>。</p><p>举例来说，在一个 TCP 连接里，服务器收到了客户端 A 和 B 的两个请求，如果发现 A 处理过程非常耗</p><p>时，于是就回应 A 请求已经处理好的部分，接着回应 B 请求，完成后，再回应 A 请求剩下的部分。</p><p><img src="'+e+'" alt="image-20220125010228444"></p><p><em>5.</em> 服务器推送</p><p>HTTP/2 还在一定程度上改善了传统的「请求 - 应答」工作模式，服务不再是被动地响应，也可以<strong>主动</strong></p><p>向客户端发送消息。</p><p>举例来说，在浏览器刚请求 HTML 的时候，就提前把可能会用到的 JS、CSS 文件等静态资源主动发给</p><p>客户端，<strong>减少延时的等待</strong>，也就是服务器推送（Server Push，也叫 Cache Push）。</p><h2 id="_3-http-2-有哪些缺陷-http-3-做了哪些优化" tabindex="-1">3.HTTP/2 有哪些缺陷？HTTP/3 做了哪些优化？ <a class="header-anchor" href="#_3-http-2-有哪些缺陷-http-3-做了哪些优化" aria-label="Permalink to &quot;3.HTTP/2 有哪些缺陷？HTTP/3 做了哪些优化？&quot;">​</a></h2><p>HTTP/2 主要的问题在于，多个 HTTP 请求在复用一个 TCP 连接，下层的 TCP 协议是不知道有多少个</p><p>HTTP 请求的。所以一旦发生了丢包现象，就会触发 TCP 的重传机制，这样在一个 TCP 连接中的<strong>所有</strong></p><p><strong>的</strong> <strong>HTTP</strong> <strong>请求都必须等待这个丢了的包被重传回来</strong>。</p><p>HTTP/1.1 中的管道（ pipeline）传输中如果有一个请求阻塞了，那么队列后请求也统统被阻塞住</p><p>了</p><p>HTTP/2 多个请求复用一个TCP连接，一旦发生丢包，就会阻塞住所有的 HTTP 请求。</p><p>这都是基于 TCP 传输层的问题，所以 <strong>HTTP/3</strong> <strong>把</strong> <strong>HTTP</strong> <strong>下层的</strong> <strong>TCP</strong> <strong>协议改成了</strong> <strong>UDP</strong>**！**</p><p><img src="'+T+'" alt="image-20220125010309686"></p><p>UDP 发生是不管顺序，也不管丢包的，所以不会出现 HTTP/1.1 的队头阻塞 和 HTTP/2 的一个丢包全</p><p>部重传问题。</p><p>大家都知道 UDP 是不可靠传输的，但基于 UDP 的 <strong>QUIC</strong> <strong>协议</strong> 可以实现类似 TCP 的可靠性传输。</p><p>QUIC 有自己的一套机制可以保证传输的可靠性的。当某个流发生丢包时，只会阻塞这个流，<strong>其他</strong></p><p><strong>流不会受到影响</strong>。</p><p>TLS3 升级成了最新的 1.3 版本，头部压缩算法也升级成了 QPack 。</p><p>HTTPS 要建立一个连接，要花费 6 次交互，先是建立三次握手，然后是 TLS/1.3 的三次握手。</p><p>QUIC 直接把以往的 TCP 和 TLS/1.3 的 6 次交互<strong>合并成了</strong> <strong>3</strong> <strong>次，减少了交互次数</strong>。</p><p><img src="'+n+'" alt="image-20220125010327465"></p><p>所以， QUIC 是一个在 UDP 之上的<strong>伪</strong> TCP + TLS + HTTP/2 的多路复用的协议。</p><p>QUIC 是新协议，对于很多网络设备，根本不知道什么是 QUIC，只会当做 UDP，这样会出现新的问</p><p>题。所以 HTTP/3 现在普及的进度非常的缓慢，不知道未来 UDP 是否能够逆袭 TCP。</p><h2 id="_4-我看文中-tls-和-ssl-没有做区分-这两个需要区分吗" tabindex="-1">4.我看文中 TLS 和 SSL 没有做区分，这两个需要区分吗？ <a class="header-anchor" href="#_4-我看文中-tls-和-ssl-没有做区分-这两个需要区分吗" aria-label="Permalink to &quot;4.我看文中 TLS 和 SSL 没有做区分，这两个需要区分吗？&quot;">​</a></h2><p>这两实际上是一个东西。</p><p>SSL 是洋文 “<em>Secure Sockets Layer</em> 的缩写，中文叫做「安全套接层」。它是在上世纪 90 年代中期，</p><p>由网景公司设计的。</p><p>到了1999年，SSL 因为应用广泛，已经成为互联网上的事实标准。IETF 就在那年把 SSL 标准化。标准</p><p>化之后的名称改为 TLS（是 “<em>Transport Layer Security</em>” 的缩写），中文叫做 「传输层安全协议」。</p><p>很多相关的文章都把这两者并列称呼（SSL/TLS），因为这两者可以视作同一个东西的不同阶段。</p><h2 id="_5-为啥-ssl-的握手是-4-次" tabindex="-1">5.为啥 ssl 的握手是 4 次？ <a class="header-anchor" href="#_5-为啥-ssl-的握手是-4-次" aria-label="Permalink to &quot;5.为啥 ssl 的握手是 4 次？&quot;">​</a></h2><p>SSL/TLS 1.2 需要 4 握手，需要 2 个 RTT 的时延，我文中的图是把每个交互分开画了，实际上把他们</p><p>合在一起发送，就是 4 次握手：</p><p><img src="'+g+'" alt="image-20220125010523105"></p><p>另外， SSL/TLS 1.3 优化了过程，只需要 1 个 RTT 往返时延，也就是只需要 3 次握手：</p><p><img src="'+P+'" alt="image-20220125010539558"></p>',80),c=[m];function _(l,h,H,S,d,C){return s(),t("div",null,c)}const f=p(i,[["render",_]]);export{L as __pageData,f as default};
